export default Visualization(({ tokens, parameters }) => {
  const { satellite_radius, planet_radius } = parameters;

  const width = 800;
  const height = 600;

  const centerX = width / 2;
  const centerY = height / 2;

  return (
    <svg
      viewBox={`0 0 ${width} ${height}`}
      style={{ borderRadius: "4px", width: "100%" }}
    >
      {/* Background */}
      <rect width={width} height={height} fill="#000014" />

      {/* Planet at center */}
      <circle
        cx={centerX}
        cy={centerY}
        r={planet_radius}
        fill="#2196f3"
        stroke="#1976d2"
        strokeWidth="2"
      />

      {/* Satellites */}
      {tokens.map(({ x, y, direction, velocity }, index) => {
        // Convert satellite coordinates to screen coordinates
        // Assuming satellite coordinates are relative to planet center
        const screenX = centerX + x;
        const screenY = centerY + y;

        return (
          <g key={index}>
            {/* Satellite */}
            <circle
              cx={screenX}
              cy={screenY}
              r={satellite_radius}
              fill="#ff5722"
              stroke="#d84315"
              strokeWidth="1"
            />

            {/* Velocity vector indicator */}
            {velocity > 0 && (
              <line
                x1={screenX}
                y1={screenY}
                x2={screenX + Math.cos(direction) * Math.log(velocity) * 10}
                y2={screenY + Math.sin(direction) * Math.log(velocity) * 10}
                stroke="#ffc107"
                strokeWidth="2"
                markerEnd="url(#arrowhead)"
              />
            )}
          </g>
        );
      })}

      {/* Arrow marker for velocity vectors */}
      <defs>
        <marker
          id="arrowhead"
          markerWidth="8"
          markerHeight="8"
          refX="7"
          refY="4"
          orient="auto"
          markerUnits="strokeWidth"
        >
          <polygon
            points="0 0, 8 4, 0 8"
            fill="#ffc107"
            stroke="#f57f17"
            strokeWidth="0.5"
          />
        </marker>
      </defs>
    </svg>
  );
});

