// When satellites collide, they become debris (lose velocity)
export default TransitionKernel((tokens) => {
  // Both satellites become stationary debris at their collision point
  return {
    Debris: [
      // Position preserved, direction and velocity zeroed
      {
        x: tokens.Space[0].x,
        y: tokens.Space[0].y,
        velocity: 0,
        direction: 0
      },
      {
        x: tokens.Space[1].x,
        y: tokens.Space[1].y,
        velocity: 0,
        direction: 0
      },
    ]
  };
})

